```
from typing import Any, Callable

import pytest
from pytest import MonkeyPatch
from unittest import mock

from langchain.docstore.document import Document
from langchain.document_loaders.recursive_url_loader import RecursiveUrlLoader


@pytest.fixture
def url_loader() -> RecursiveUrlLoader:
    url = "http://test.com"
    exclude_dir = "/exclude"  # Note: Changed from list to single string
    return RecursiveUrlLoader(url, exclude_dir)


@pytest.fixture
def mock_web_base_loader_load(monkeypatch: MonkeyPatch) -> None:
    """Mock requests.get"""

    # Mock Document object for first page
    mock_doc_page1 = Document(
        page_content='<a href="/page2">',  # This page has a link to the second page
        metadata={"url": "http://test.com/page1"}
    )

    # Mock Document object for second page
    mock_doc_page2 = Document(
        page_content="This is page 2",  # This page doesn't link to anything
        metadata={"url": "http://test.com/page2"}
    )

    def mock_get(url: str, *args: Any, **kwargs: Any) -> Document:
        if url == "http://test.com/page1":
            return mock_doc_page1
        elif url == "http://test.com/page2":
            return mock_doc_page2

        default_doc = Document(
            page_content="Default page", metadata={"url": "http://test.com/default"}
        )
        return default_doc

    monkeypatch.setattr("langchain.document_loaders.WebBaseLoader.load", mock_get)

def test_get_child_links_recursive(url_loader: RecursiveUrlLoader, monkeypatch: MonkeyPatch) -> None:
    mock_response1 = mock.Mock()
    mock_response1.status_code = 200
    mock_response1.text = '<html><body><a href="/page2"></a></body></html>'

    mock_response2 = mock.Mock()
    mock_response2.status_code = 200
    mock_response2.text = 'This is page 2'

    # Mock Document objects
    mock_doc_page1 = Document(page_content=mock_response1.text, metadata={"url": "http://test.com/page1"})
    mock_doc_page2 = Document(page_content=mock_response2.text, metadata={"url": "http://test.com/page2"})

    def mock_load(self):
        if self.url == "http://test.com/page1":
            return mock_doc_page1
        elif self.url == "http://test.com/page2":
            return mock_doc_page2

    monkeypatch.setattr("langchain.document_loaders.WebBaseLoader.load", mock_load)

    def mock_get(url: str, *args: Any, **kwargs: Any) -> Any:
        if url == "http://test.com/page1":
            return mock_response1
        elif url == "http://test.com/page2":
            return mock_response2

    with mock.patch('requests.get', new=mock_get):
        child_docs = list(url_loader.get_child_links_recursive("http://test.com/page1"))

    assert len(child_docs) == 2
    assert child_docs[0] == mock_doc_page1
    assert child_docs[1] == mock_doc_page2
```

